#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int h[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &h[i]);
        }
        int maxTravelTime = 0;
        for (int i = 0; i < n; i++) {
            int travelTime = h[i] + h[(i + n / 2) % n] + n / 2;
            maxTravelTime = (travelTime > maxTravelTime) ? travelTime : maxTravelTime;
        }
        printf("%d\n", maxTravelTime);
    }
    return 0;
}

