const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];

const T = parseInt(readline());
for (let t = 0; t < T; t++) {
    const n = parseInt(readline().split(' ')[0]);
    const h = readline().split(' ').map(Number);
    let maxTravelTime = 0;
    for (let i = 0; i < n; i++) {
        const travelTime = h[i] + h[(i + Math.floor(n / 2)) % n] + Math.floor(n / 2);
        maxTravelTime = Math.max(travelTime, maxTravelTime);
    }
    console.log(maxTravelTime);
}
